1	/**
2	 * CHR-V3-08 — ToolModifierBar presentational component.
3	 *
4	 * 36 px secondary contextual bar that morphs by active tool. Mounts when
5	 * a tool with registered descriptors is active; unmounts when no tool is
6	 * active (D8 — context, not configuration). Does not persist between tool
7	 * sessions.
8	 *
9	 * All colours via CSS custom properties — no hex literals (R-G §2.5).
10	 */
11	
12	import { type JSX } from 'react';
13	
14	import type { ToolId } from './toolRegistry';
15	import type {
16	  AlwaysArmedModifierDescriptor,
17	  CycleModifierDescriptor,
18	  ToggleModifierDescriptor,
19	  ToolModifierDescriptor,
20	} from './modifierBar';
21	
22	export interface ToolModifierBarProps {
23	  activeTool: ToolId | null;
24	  descriptors: ToolModifierDescriptor[];
25	  getToggle: (modifierId: string) => boolean;
26	  onToggle: (modifierId: string, value: boolean) => void;
27	  getCycle: (modifierId: string) => string;
28	  onCycleAdvance: (modifierId: string) => void;
29	}
30	
31	const BAR_STYLE: React.CSSProperties = {
32	  display: 'flex',
33	  alignItems: 'center',
34	  gap: 16,
35	  height: 36,
36	  paddingInline: 12,
37	  background: 'var(--color-surface-2, var(--color-surface-strong))',
38	  borderBottom: '1px solid var(--color-border)',
39	  fontSize: 'var(--text-xs)',
40	  lineHeight: 'var(--text-xs-line)',
41	  color: 'var(--color-foreground)',
42	  overflow: 'hidden',
43	  animation: 'modifier-bar-mount 200ms var(--ease-paper, cubic-bezier(0.32,0.72,0,1)) both',
44	};
45	
46	const LABEL_STYLE: React.CSSProperties = {
47	  color: 'var(--color-muted-foreground)',
48	  fontVariantNumeric: 'tabular-nums',
49	  whiteSpace: 'nowrap',
50	};
51	
52	const CHIP_STYLE: React.CSSProperties = {
53	  display: 'inline-flex',
54	  alignItems: 'center',
55	  justifyContent: 'center',
56	  padding: '0 5px',
57	  height: 18,
58	  borderRadius: 3,
59	  fontSize: 'var(--text-2xs, 10px)',
60	  lineHeight: 'var(--text-2xs-line, 14px)',
61	  background: 'var(--color-surface-strong)',
62	  border: '1px solid var(--color-border)',
63	  color: 'var(--color-muted-foreground)',
64	  fontFamily: 'var(--font-mono, monospace)',
65	};
66	
67	const TOGGLE_ON_STYLE: React.CSSProperties = {
68	  display: 'inline-flex',
69	  alignItems: 'center',
70	  gap: 5,
71	  cursor: 'pointer',
72	  padding: '2px 7px',
73	  borderRadius: 4,
74	  background: 'var(--color-accent-soft)',
75	  border: '1px solid var(--color-accent)',
76	  color: 'var(--color-foreground)',
77	  fontSize: 'inherit',
78	  lineHeight: 'inherit',
79	};
80	
81	const TOGGLE_OFF_STYLE: React.CSSProperties = {
82	  display: 'inline-flex',
83	  alignItems: 'center',
84	  gap: 5,
85	  cursor: 'pointer',
86	  padding: '2px 7px',
87	  borderRadius: 4,
88	  background: 'transparent',
89	  border: '1px solid var(--color-border)',
90	  color: 'var(--color-muted-foreground)',
91	  fontSize: 'inherit',
92	  lineHeight: 'inherit',
93	};
94	
95	const CYCLE_STYLE: React.CSSProperties = {
96	  display: 'inline-flex',
97	  alignItems: 'center',
98	  gap: 5,
99	  cursor: 'pointer',
100	  padding: '2px 7px',
101	  borderRadius: 4,
102	  background: 'transparent',
103	  border: '1px solid var(--color-border)',
104	  color: 'var(--color-foreground)',
105	  fontSize: 'inherit',
106	  lineHeight: 'inherit',
107	};
108	
109	const ALWAYS_ARMED_STYLE: React.CSSProperties = {
110	  display: 'inline-flex',
111	  alignItems: 'center',
112	  gap: 5,
113	  color: 'var(--color-muted-foreground)',
114	  opacity: 0.7,
115	  fontSize: 'inherit',
116	  lineHeight: 'inherit',
117	};
118	
119	const SEPARATOR_STYLE: React.CSSProperties = {
120	  width: 1,
121	  height: 18,
122	  background: 'var(--color-border)',
123	  flexShrink: 0,
124	};
125	
126	function ToggleChip({
127	  descriptor,
128	  on,
129	  onToggle,
130	}: {
131	  descriptor: ToggleModifierDescriptor;
132	  on: boolean;
133	  onToggle: (value: boolean) => void;
134	}): JSX.Element {
135	  return (
136	    <button
137	      type="button"
138	      role="switch"
139	      aria-checked={on}
140	      aria-label={descriptor.label}
141	      data-testid={`modifier-toggle-${descriptor.id}`}
142	      style={on ? TOGGLE_ON_STYLE : TOGGLE_OFF_STYLE}
143	      onClick={() => onToggle(!on)}
144	    >
145	      <span style={LABEL_STYLE}>{descriptor.label}</span>
146	      {descriptor.shortcut && <span style={CHIP_STYLE}>{descriptor.shortcut}</span>}
147	    </button>
148	  );
149	}
150	
151	function CycleChip({
152	  descriptor,
153	  current,
154	  onAdvance,
155	}: {
156	  descriptor: CycleModifierDescriptor;
157	  current: string;
158	  onAdvance: () => void;
159	}): JSX.Element {
160	  const displayLabel = descriptor.valueLabels[current] ?? current;
161	  return (
162	    <button
163	      type="button"
164	      aria-label={`${descriptor.label}: ${displayLabel}`}
165	      data-testid={`modifier-cycle-${descriptor.id}`}
166	      style={CYCLE_STYLE}
167	      onClick={onAdvance}
168	    >
169	      <span style={LABEL_STYLE}>{descriptor.label}:</span>
170	      <span>{displayLabel}</span>
171	      {descriptor.shortcut && <span style={CHIP_STYLE}>{descriptor.shortcut}</span>}
172	    </button>
173	  );
174	}
175	
176	function AlwaysArmedChip({
177	  descriptor,
178	}: {
179	  descriptor: AlwaysArmedModifierDescriptor;
180	}): JSX.Element {
181	  return (
182	    <span data-testid={`modifier-armed-${descriptor.id}`} style={ALWAYS_ARMED_STYLE}>
183	      <span>{descriptor.label}</span>
184	      {descriptor.shortcut && <span style={CHIP_STYLE}>{descriptor.shortcut}</span>}
185	    </span>
186	  );
187	}
188	
189	export function ToolModifierBar({
190	  activeTool,
191	  descriptors,
192	  getToggle,
193	  onToggle,
194	  getCycle,
195	  onCycleAdvance,
196	}: ToolModifierBarProps): JSX.Element | null {
197	  if (!activeTool || descriptors.length === 0) return null;
198	
199	  const chips: JSX.Element[] = [];
200	  let prevKind: string | null = null;
201	
202	  for (const desc of descriptors) {
203	    if (prevKind === 'always-armed' && desc.kind !== 'always-armed') {
204	      chips.push(<div key={`sep-${desc.id}`} style={SEPARATOR_STYLE} aria-hidden="true" />);
205	    } else if (prevKind !== null && prevKind !== 'always-armed' && desc.kind === 'always-armed') {
206	      chips.push(<div key={`sep-${desc.id}`} style={SEPARATOR_STYLE} aria-hidden="true" />);
207	    }
208	
209	    if (desc.kind === 'toggle') {
210	      chips.push(
211	        <ToggleChip
212	          key={desc.id}
213	          descriptor={desc}
214	          on={getToggle(desc.id)}
215	          onToggle={(v) => onToggle(desc.id, v)}
216	        />,
217	      );
218	    } else if (desc.kind === 'cycle') {
219	      chips.push(
220	        <CycleChip
221	          key={desc.id}
222	          descriptor={desc}
223	          current={getCycle(desc.id)}
224	          onAdvance={() => onCycleAdvance(desc.id)}
225	        />,
226	      );
227	    } else {
228	      chips.push(<AlwaysArmedChip key={desc.id} descriptor={desc} />);
229	    }
230	    prevKind = desc.kind;
231	  }
232	
233	  return (
234	    <>
235	      <style>{`
236	        @keyframes modifier-bar-mount {
237	          from { opacity: 0; transform: translateY(-4px); }
238	          to   { opacity: 1; transform: translateY(0); }
239	        }
240	      `}</style>
241	      <div
242	        role="toolbar"
243	        aria-label={`${activeTool} modifiers`}
244	        data-testid="tool-modifier-bar"
245	        style={BAR_STYLE}
246	      >
247	        {chips}
248	      </div>
249	    </>
250	  );
251	}
252

