const hotkeyTool = tools.find((t) => t.hotkey === hotkeyLabel);
// Whether pressing this key could start a two-char shortcut chord
const isChordStart =
  !event.shiftKey &&
  tools.some((t) => t.shortcut?.length === 2 && t.shortcut[0] === upper);

